from __future__ import annotations


def management_report_dashboard_html() -> str:
    return r'''<!doctype html><html lang="ru"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Отчёт для руководства — AI-BIT</title><style>
:root{color-scheme:light;--bg:#f7f8fa;--surface:#fff;--surface2:#fbfbfc;--line:#e6e8ec;--text:#17191c;--muted:#73777f;--accent:#5e6ad2;--accent-soft:#f0f1ff;--ok:#1f9d68;--warn:#c47a13;--bad:#d84a5f}*{box-sizing:border-box}body{margin:0;background:var(--bg);color:var(--text);font:14px/1.5 Inter,ui-sans-serif,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;-webkit-font-smoothing:antialiased}main{max-width:1220px;margin:auto;padding:34px 34px 90px}.hero{display:flex;justify-content:space-between;gap:24px;align-items:flex-start;padding-bottom:22px;border-bottom:1px solid var(--line);margin-bottom:22px}.eyebrow{font-size:11px;text-transform:uppercase;letter-spacing:.11em;font-weight:700;color:var(--muted);margin-bottom:8px}.hero h1{margin:0;font-size:27px;line-height:1.2;letter-spacing:-.03em}.hero p,.muted{color:var(--muted)}.actions{display:flex;gap:8px;flex-wrap:wrap}.btn,button{border:1px solid var(--line);background:var(--surface);color:#42464d;padding:8px 11px;border-radius:8px;text-decoration:none;cursor:pointer;box-shadow:0 1px 2px rgba(17,24,39,.03);transition:.16s ease}.btn:hover,button:hover{border-color:var(--line2,#d3d6dc);background:#f8f8f9;color:var(--text)}.primary{background:var(--text);border-color:var(--text);color:#fff}.primary:hover{background:#2a2d31;color:#fff}.grid{display:grid;grid-template-columns:1.35fr repeat(4,1fr);gap:12px}.card,.section{background:var(--surface);border:1px solid var(--line);border-radius:12px;padding:18px;box-shadow:0 1px 2px rgba(17,24,39,.025)}.card{min-height:114px}.section{margin-top:14px}.score{font-size:48px;font-weight:730;line-height:1;letter-spacing:-.045em;margin-top:10px}.value{font-size:28px;font-weight:720;letter-spacing:-.035em;margin:10px 0 4px}.label{font-size:12px;color:var(--muted)}.ok{color:var(--ok)}.warn{color:var(--warn)}.bad{color:var(--bad)}.summary-text{font-size:16px;line-height:1.72;max-width:920px}.decision{padding:14px 15px;border-radius:10px;background:var(--accent-soft);border:1px solid #dfe1ff;margin:14px 0 0}.decision b{display:block;margin-bottom:4px}.links{display:grid;grid-template-columns:repeat(3,1fr);gap:10px}.link-card{display:block;padding:16px;border:1px solid var(--line);border-radius:10px;background:var(--surface2);color:var(--text);text-decoration:none;transition:.16s ease}.link-card:hover{border-color:#c9cdf7;background:#f7f7ff;transform:translateY(-1px);box-shadow:0 5px 16px rgba(17,24,39,.05)}details{margin-top:14px;border:1px solid var(--line);border-radius:11px;padding:14px;background:var(--surface)}summary{cursor:pointer;font-weight:680}.row{display:grid;grid-template-columns:1fr auto;gap:10px;padding:11px 0;border-bottom:1px solid #eff0f2}.row:last-child{border:0}.empty{color:var(--muted);padding:20px;text-align:center}h2{font-size:16px;margin:0 0 14px;letter-spacing:-.01em}@media(max-width:1050px){.grid{grid-template-columns:repeat(2,1fr)}.links{grid-template-columns:repeat(2,1fr)}}@media(max-width:650px){main{padding:22px 16px 70px}.hero{display:block}.actions{margin-top:14px}.grid,.links{grid-template-columns:1fr}}
</style></head><body><main><div class="hero"><div><div class="eyebrow">AI-BIT Enterprise</div><h1>Отчёт для руководства</h1><p>Краткий управленческий вывод за 30 секунд. Детальная аналитика вынесена в специализированные разделы.</p><div id="updated" class="muted">Загрузка последнего подтверждённого снимка…</div></div><div class="actions"><button id="refresh" class="primary">Обновить данные</button><a class="btn" href="/about" target="_top">О системе</a></div></div><div id="content"><div class="section empty">Формируется управленческая сводка…</div></div><details><summary>Подробный отчёт и история PDF</summary><div class="actions" style="margin-top:14px"><button id="generate">Сформировать подробный PDF</button><a class="btn" href="/management-reports" target="_top">История отчётов</a></div><div id="reportStatus" class="muted" style="margin-top:10px"></div></details></main><script>
const $=s=>document.querySelector(s);const esc=v=>{const d=document.createElement('div');d.textContent=v??'';return d.innerHTML};const num=v=>new Intl.NumberFormat('ru-RU',{maximumFractionDigits:1}).format(Number(v||0));const money=v=>new Intl.NumberFormat('ru-RU').format(Math.round(Number(v||0)))+' ₸';const cls=v=>Number(v)>=75?'ok':Number(v)>=55?'warn':'bad';
function conclusionText(d){const c=d.management_conclusion||{};if(c.executive_summary)return c.executive_summary;if(c.summary)return c.summary;const s=d.source_summary||{},m=d.digital_maturity||{};return 'Система используется в рабочем режиме. Общая оценка составляет '+num(m.score)+' из 100. Просрочка открытых задач — '+num(s.overdue_rate)+'%, задач без срока — '+(s.without_deadline||0)+'. Основной управленческий приоритет — усилить контроль исполнения и завершить внедрение ключевых цифровых процессов.'}
function nextAction(d){const c=d.ai_cio||{},r=(c.recommendations||[])[0];if(r)return r.title;const roots=((d.executive_kpi||{}).root_causes||[])[0];return roots?.recommended_action||'Утвердить ответственных и сроки по ключевым направлениям внедрения.'}
function render(d){const m=d.digital_maturity||{},s=d.source_summary||{},bv=((d.business_value||{}).total)||{},k=d.executive_kpi||{},roots=(k.root_causes||[]).slice(0,3),risks=(d.risks||[]).slice(0,3);const critical=risks.filter(x=>x.severity==='critical'||x.severity==='high').length;const html='<div class="grid"><div class="card"><div class="label">Общая оценка внедрения</div><div class="score '+cls(m.score)+'">'+esc(num(m.score))+'</div><div class="muted">из 100 · '+esc(m.level||'')+'</div></div><div class="card"><div class="label">Критичных проблем</div><div class="value bad">'+esc(critical)+'</div></div><div class="card"><div class="label">Просрочка</div><div class="value bad">'+esc(num(s.overdue_rate))+'%</div></div><div class="card"><div class="label">Без срока</div><div class="value warn">'+esc(s.without_deadline||0)+'</div></div><div class="card"><div class="label">Потенциальный эффект</div><div class="value ok" style="font-size:20px">'+esc(money(bv.annual_saving_kzt))+'</div><div class="muted">в год</div></div></div><section class="section"><h2>Управленческий вывод</h2><div class="summary-text">'+esc(conclusionText(d))+'</div><div class="decision"><b>Следующее действие</b><div>'+esc(nextAction(d))+'</div></div></section><section class="section"><h2>Детальная аналитика</h2><div class="links"><a class="link-card" href="/digital-passport" target="_top"><b>Цифровой паспорт</b><br><span class="muted">Зрелость всех направлений на одном экране</span></a><a class="link-card" href="/process-optimizer" target="_top"><b>Оптимизация процессов</b><br><span class="muted">Рейтинг процессов и узкие места</span></a><a class="link-card" href="/ai-cio" target="_top"><b>AI CIO</b><br><span class="muted">Приоритетные решения на 90 дней</span></a><a class="link-card" href="/transformation-roadmap" target="_top"><b>Дорожная карта</b><br><span class="muted">Этапы, сроки и ответственные</span></a><a class="link-card" href="/risk-forecast" target="_top"><b>Прогноз рисков</b><br><span class="muted">Динамика и ожидаемые отклонения</span></a><a class="link-card" href="/business-value" target="_top"><b>Бизнес-эффект</b><br><span class="muted">Экономия времени и денег</span></a></div></section><details><summary>Почему система сделала такой вывод</summary><section class="section">'+(roots.length?roots.map(x=>'<div class="row"><div><b>'+esc(x.title||x.fact||'Отклонение')+'</b><div class="muted">'+esc(x.root_cause||x.business_impact||'')+'</div></div><span>'+esc(x.confidence||0)+'%</span></div>').join(''):'<div class="empty">Подтверждённые корневые причины не сформированы.</div>')+'</section></details>';$('#content').innerHTML=html;$('#updated').textContent='Данные обновлены: '+new Date(d.generated_at).toLocaleString('ru-RU')}
async function latest(){const r=await fetch('/executive-intelligence/latest');const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка загрузки');render(d)}async function refresh(){try{$('#updated').textContent='Выполняется обновление…';const r=await fetch('/executive-intelligence/collect',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка обновления');render(d)}catch(e){$('#updated').textContent='Не удалось обновить данные. Показан последний снимок.';try{await latest()}catch(_){$('#content').innerHTML='<div class="section bad">'+esc(e.message)+'</div>'}}}$('#refresh').onclick=refresh;$('#generate').onclick=async()=>{try{$('#generate').disabled=true;$('#reportStatus').textContent='Формируется подробный PDF…';const r=await fetch('/management-reports/generate?mode=detailed',{method:'POST'});const d=await r.json();if(!r.ok)throw new Error(d.detail||'Ошибка');$('#reportStatus').innerHTML='Отчёт готов: <a href="/management-reports/'+esc(d.id)+'/pdf" target="_blank">открыть PDF</a>'}catch(e){$('#reportStatus').textContent='Ошибка: '+e.message}finally{$('#generate').disabled=false}};latest().catch(()=>refresh());
</script></body></html>'''
